import{_ as e,o as t,c as r,j as o}from"./chunks/framework.ETe_P6d1.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reports/何晶晶/何晶晶_何晶晶_何晶晶 关于开平碉楼建筑的调研报告.md","filePath":"reports/何晶晶/何晶晶_何晶晶_何晶晶 关于开平碉楼建筑的调研报告.md"}'),a={name:"reports/何晶晶/何晶晶_何晶晶_何晶晶 关于开平碉楼建筑的调研报告.md"};function s(n,_,p,l,c,d){return t(),r("div",null,[..._[0]||(_[0]=[o("p",null,"考察地点： 广东省江门市开平市 考察时间： 2026年3月31日 学生姓名： 何晶晶 指导教师： 石拓教授 开平碉楼观察报告：从材料运用与建造智慧中的中西文化对话 一、引言：研究问题的提出 开平碉楼作为世界文化遗产，其独特性不仅在于中西合璧的视觉表象，更在于材料与建造技术所承载的文化对话机制。当站在立园泮立楼前，触摸那些意大利进口的彩色水磨石地面，或仰望赤坎古镇骑楼立面上的青砖与红砖交错，实际上正在见证一场跨越地理与文化的建筑实验。 本研究以实地观察的立园与赤坎古镇骑楼群为案例，结合《开平碉楼》（广东省文物考古研究所）的考古发现与《华侨建筑文化研究》的理论框架，提出研究课题：乡土建筑如何通过材料的选择与组合和建造特点实现中西文化的物理性对话？ 二、案例分析：材料表达与建造智慧的对比观察 立园泮立楼：进口材料的本土化转译 泮立楼建于1931年，为居楼式碉楼，建筑投影面积146平方米，长12.6米、宽11.6米，高三层半。其平面布局呈现防御性居住空间的典型特征。底层设置厨房与储藏室，这是防御最严密的楼层，铁栅门窗紧闭。二层为客厅与餐厅，承担家族公共活动功能。三层为卧室，属于私密空间。顶层则设祖先神位与避难室，既是精神中心也是最后防线。 这种空间序列遵循外闭内敞的原则。外部铁栅紧闭、窗户狭小，形成严密的防御外壳。内部则通过意大利彩石楼梯串联各层，形成垂直向的家族生活轴线。这种布局体现了《开平碉楼》中所述的居楼类型特征：富户独建，集防卫与居住于一体。 楼顶铺设中国古式琉璃瓦，采用传统重檐构造与歇山顶形式，维护了岭南建筑的身份标识。门窗使用德国厚钢板，以铁板包框配合铁栅，形成 bullet-proof 的防御设计。墙面装饰则运用本地灰塑与潮汕金漆木雕，通过传统工艺现场制作，强化地方文化认同。钢筋混凝土确保结构安全以满足防御需求，意大利水磨石展示海外财富以彰显身份象征，琉璃瓦顶维持乡土认同以巩固文化归属。 青砖与红砖交错磨砌筑，创造了17种柱式、35种窗户、25种栏杆。这种旧材新用的实践，延续了碉楼时代的建造智慧。当年华侨从海外带回图纸，本土工匠现场勾画草图、砌筑大样，形成即时创作的传统。 一些地面进行修补，对铁窗进行防锈处理。 在功能植入方面，立园面临从私人居住到公共展示的转变。原有卧室、客厅被改造为展室，展示华侨家族生活场景。这种改造程度属于局部更新，通过可逆性展陈设计，避免对原有空间造成永久性改变。然而，这种博物馆化改造也带来了使用真实性的丧失。原有水磨石地面铺设保护性覆盖层，游客无法直接触摸材料质感；铁窗长期紧闭，失去了原有的通风与防御功能。 赤坎古镇的活态遗产的可持续性实验 2023年完成的赤坎华侨古镇项目，采用整体改造与活态传承相结合的模式。在600座骑楼中，约200座进行结构性修缮，100座进行立面整治，其余保持原状作为背景景观。 改造中的材料运用体现了当代建造智慧与传统技艺的对话。侨小馆项目回收古窑青砖与红砖，通过手工打磨去除表面风化层，重新砌筑时采用传统糯米灰浆，确保新旧材料的相容性。然而，为满足现代建筑规范，内部结构植入钢筋混凝土框架，形成砖混结构，这与原有砖木结构或砖混结构在力学性能上存在本质差异。 功能植入方面，赤坎骑楼从传统商住混合转变为文旅商业复合体。一层恢复骑楼廊道传统商业功能，引入图书馆、咖啡馆、手工艺店、非遗展示、剧情空间等业态；二层以上改造为民宿或办公空间。这种改造在保留立面原貌的同时，彻底改变了内部空间组织。原有木楼板被混凝土楼板替代，以满足消防与隔音要求；传统天井被玻璃顶棚覆盖，形成室内中庭，改变了原有的微气候调节机制。 改造效果的评价呈现矛盾性。从保护角度，立面的原真性得到维持，青砖与红砖的质感、西式柱式的比例、灰塑装饰的题材均得以保留。从使用角度，新功能激活了建筑的经济价值，避免了空置衰败。 当您下次触摸那些水磨石地面，希望您不仅感受到百年前的跨洋旅程，更能思考这些材料在当代的延续与转化可能。 参考文献 广东省文物考古研究所. (2010). 开平碉楼. 文物出版社. 华侨大学建筑学院. (2015). 华侨建筑文化研究. 华侨大学出版社. 阮仪三, 王景慧. (2013). 文化遗产保护的理论与实践. 同济大学出版社. 关询维. (2023). 赤坎古镇骑楼群建筑特色分析. 广州日报. 开平市文物局. (2025). 立园古建筑群介绍. 广东省",-1)])])}const m=e(a,[["render",s]]);export{f as __pageData,m as default};
